namespace GstService.IntegrationTests;

/// <summary>
/// Integration tests for the GST Service API endpoints.
/// Uses Testcontainers (PostgreSQL 17) matching the same pattern as
/// AuthService.IntegrationTests and CallbackService.IntegrationTests.
///
/// Blocked by P6-INT-02: InternalsVisibleTo not yet added to GstService.Api.csproj.
/// Author status: COMPLETE — pending CI Docker socket and InternalsVisibleTo.
/// </summary>
[Collection("GstApi")]
public class GstNoticeIntegrationTests : IAsyncLifetime
{
    private readonly PostgreSqlContainer _postgres = new PostgreSqlBuilder()
        .WithImage("postgres:17-alpine")
        .WithDatabase("snapaccount_test")
        .WithUsername("postgres")
        .WithPassword("postgres_test")
        .Build();

    private HttpClient _client = null!;
    private WebApplicationFactory<Program> _factory = null!;

    // ──────────────────────────────────────────────────────────────
    // IAsyncLifetime
    // ──────────────────────────────────────────────────────────────

    public async Task InitializeAsync()
    {
        await _postgres.StartAsync();

        _factory = new WebApplicationFactory<Program>()
            .WithWebHostBuilder(builder =>
            {
                builder.UseEnvironment("Testing");
                builder.ConfigureServices(services =>
                {
                    // Replace EF Core connection string with the test container
                    services.RemoveAll<DbContextOptions>();
                    services.RemoveAll<DbContextOptions<GstDbContext>>();

                    services.AddDbContext<GstDbContext>(options =>
                        options.UseNpgsql(_postgres.GetConnectionString()));
                });
            });

        _client = _factory.CreateClient();

        // Apply EF Core migrations to the test container
        using var scope = _factory.Services.CreateScope();
        var db = scope.ServiceProvider.GetRequiredService<GstDbContext>();
        await db.Database.MigrateAsync();
    }

    public async Task DisposeAsync()
    {
        _client.Dispose();
        await _factory.DisposeAsync();
        await _postgres.DisposeAsync();
    }

    // ──────────────────────────────────────────────────────────────
    // Notice Upload — P6-HANDOFF-14
    // ──────────────────────────────────────────────────────────────

    /// <summary>
    /// Happy path: POST /gst/notices with valid payload should return 201 Created
    /// and the created notice's ID.
    /// P6-HANDOFF-14: Notice upload endpoint must accept attachment metadata.
    /// </summary>
    [Fact(Skip = "P6-INT-02: InternalsVisibleTo not yet configured on GstService.Api")]
    public async Task PostGstNotice_ValidPayload_Returns201WithId()
    {
        // Arrange
        var request = new
        {
            organizationId = Guid.NewGuid().ToString(),
            gstin = "27AABCS1429B1ZB",
            noticeNumber = "ASMT-10-2024-001",
            noticeType = "ASMT-10",
            noticeDate = "2026-03-01T00:00:00Z",
            dueDate = "2026-04-30T00:00:00Z",
            description = "Mismatch in GSTR-3B vs GSTR-1 for March 2024",
            attachments = new[]
            {
                new
                {
                    fileName = "notice.pdf",
                    fileSizeBytes = 204800,
                    gcsUri = "gs://snapaccount-test/gst/notices/notice.pdf",
                    contentType = "application/pdf",
                }
            }
        };

        // Act
        var response = await _client.PostAsJsonAsync("/gst/notices", request);

        // Assert
        response.StatusCode.Should().Be(HttpStatusCode.Created);
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        body.TryGetProperty("id", out var id).Should().BeTrue();
        id.GetString().Should().NotBeNullOrEmpty();
    }

    /// <summary>
    /// Error path: POST /gst/notices with invalid attachment metadata
    /// (missing gcsUri) should return 400 Bad Request.
    /// P6-HANDOFF-14: Attachment metadata validation must reject missing GCS URI.
    /// </summary>
    [Fact(Skip = "P6-INT-02: InternalsVisibleTo not yet configured on GstService.Api")]
    public async Task PostGstNotice_InvalidAttachmentMetadata_Returns400()
    {
        // Arrange — attachment is missing required gcsUri
        var request = new
        {
            organizationId = Guid.NewGuid().ToString(),
            gstin = "27AABCS1429B1ZB",
            noticeNumber = "ASMT-10-2024-002",
            noticeType = "ASMT-10",
            noticeDate = "2026-03-01T00:00:00Z",
            description = "Test",
            attachments = new[]
            {
                new
                {
                    fileName = "bad.pdf",
                    fileSizeBytes = 100,
                    // gcsUri intentionally omitted
                }
            }
        };

        // Act
        var response = await _client.PostAsJsonAsync("/gst/notices", request);

        // Assert
        response.StatusCode.Should().Be(HttpStatusCode.BadRequest);
    }

    // ──────────────────────────────────────────────────────────────
    // Notice Upload — missing required fields
    // ──────────────────────────────────────────────────────────────

    /// <summary>
    /// Error path: POST /gst/notices with missing GSTIN returns 400.
    /// </summary>
    [Fact(Skip = "P6-INT-02: InternalsVisibleTo not yet configured on GstService.Api")]
    public async Task PostGstNotice_MissingGstin_Returns400()
    {
        var request = new
        {
            organizationId = Guid.NewGuid().ToString(),
            noticeNumber = "ASMT-10-2024-003",
            noticeType = "ASMT-10",
            noticeDate = "2026-03-01T00:00:00Z",
            description = "Test",
        };

        var response = await _client.PostAsJsonAsync("/gst/notices", request);

        response.StatusCode.Should().Be(HttpStatusCode.BadRequest);
    }
}

/// <summary>
/// Integration tests for HSN/SAC search endpoint.
/// </summary>
[Collection("GstApi")]
public class GstHsnSacIntegrationTests : IAsyncLifetime
{
    private readonly PostgreSqlContainer _postgres = new PostgreSqlBuilder()
        .WithImage("postgres:17-alpine")
        .WithDatabase("snapaccount_test")
        .WithUsername("postgres")
        .WithPassword("postgres_test")
        .Build();

    private HttpClient _client = null!;
    private WebApplicationFactory<Program> _factory = null!;

    public async Task InitializeAsync()
    {
        await _postgres.StartAsync();

        _factory = new WebApplicationFactory<Program>()
            .WithWebHostBuilder(builder =>
            {
                builder.UseEnvironment("Testing");
                builder.ConfigureServices(services =>
                {
                    services.RemoveAll<DbContextOptions>();
                    services.RemoveAll<DbContextOptions<GstDbContext>>();
                    services.AddDbContext<GstDbContext>(options =>
                        options.UseNpgsql(_postgres.GetConnectionString()));
                });
            });

        _client = _factory.CreateClient();

        using var scope = _factory.Services.CreateScope();
        var db = scope.ServiceProvider.GetRequiredService<GstDbContext>();
        await db.Database.MigrateAsync();
    }

    public async Task DisposeAsync()
    {
        _client.Dispose();
        await _factory.DisposeAsync();
        await _postgres.DisposeAsync();
    }

    /// <summary>
    /// Happy path: GET /gst/hsn-sac?query=wheat should return ranked results.
    /// Verifies that the HSN/SAC search endpoint is wired up and returns items.
    /// </summary>
    [Fact(Skip = "P6-INT-02: InternalsVisibleTo not yet configured on GstService.Api")]
    public async Task GetHsnSac_ValidQuery_ReturnsRankedResults()
    {
        // Act
        var response = await _client.GetAsync("/gst/hsn-sac?query=wheat&limit=10");

        // Assert
        response.StatusCode.Should().Be(HttpStatusCode.OK);
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        body.TryGetProperty("items", out var items).Should().BeTrue();
        items.ValueKind.Should().Be(JsonValueKind.Array);
    }

    /// <summary>
    /// Error path: GET /gst/hsn-sac with empty query returns 400 or empty result.
    /// The endpoint must not crash on a blank search term.
    /// </summary>
    [Fact(Skip = "P6-INT-02: InternalsVisibleTo not yet configured on GstService.Api")]
    public async Task GetHsnSac_EmptyQuery_Returns200WithEmptyItems()
    {
        // Act
        var response = await _client.GetAsync("/gst/hsn-sac?query=&limit=10");

        // Assert — either 200 with empty items, or 400 (both are acceptable)
        response.StatusCode.Should().BeOneOf(HttpStatusCode.OK, HttpStatusCode.BadRequest);
    }

    /// <summary>
    /// Verifies the search respects the limit parameter (max 10).
    /// </summary>
    [Fact(Skip = "P6-INT-02: InternalsVisibleTo not yet configured on GstService.Api")]
    public async Task GetHsnSac_WithLimit10_ReturnsAtMost10Items()
    {
        // Act
        var response = await _client.GetAsync("/gst/hsn-sac?query=service&limit=10");

        // Assert
        response.StatusCode.Should().Be(HttpStatusCode.OK);
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var items = body.GetProperty("items");
        items.GetArrayLength().Should().BeLessOrEqualTo(10);
    }
}
